+        public static void SeedCourses(SchoolContext context)
+        {
+            context.Courses.AddRange(
+                new Course { CourseID = 1050, Title = "Chemistry", Credits = 3, DepartmentID = 1 },
+                new Course { CourseID = 4022, Title = "Microeconomics", Credits = 3, DepartmentID = 2 },
+                new Course { CourseID = 4041, Title = "Macroeconomics", Credits = 3, DepartmentID = 2 },
+                new Course { CourseID = 1045, Title = "Calculus", Credits = 4, DepartmentID = 3 }
+            );
+            context.SaveChanges();
+        }
+
+        public static void SeedEnrollments(SchoolContext context)
+        {
+            context.Enrollments.AddRange(
+                new Enrollment { CourseID = 1050, StudentID = 1, Grade = Grade.A },
+                new Enrollment { CourseID = 4022, StudentID = 1, Grade = Grade.C },
+                new Enrollment { CourseID = 4041, StudentID = 2, Grade = Grade.B },
+                new Enrollment { CourseID = 1045, StudentID = 3, Grade = null }
+            );
+            context.SaveChanges();
+        }
+
+        public static void SeedAll(SchoolContext context)
+        {
+            SeedInstructors(context);
+            SeedDepartments(context);
+            SeedCourses(context);
+            SeedStudents(context);
+            SeedEnrollments(context);
+        }
+    }
+}
