+using ContosoUniversity.Models;
+using ContosoUniversity.Services;
+
+namespace ContosoUniversity.Tests.Services
+{
+    public class NotificationServiceTests : IDisposable
+    {
+        private readonly NotificationService _service;
+
+        public NotificationServiceTests()
+        {
+            _service = new NotificationService();
+            // Drain static queue to avoid test interference
+            while (_service.ReceiveNotification() != null) { }
+        }
+
+        public void Dispose()
+        {
+            // Drain queue after each test
+            while (_service.ReceiveNotification() != null) { }
+            _service.Dispose();
+        }
+
+        [Fact]
+        public void SendNotification_WithDisplayName_Create_GeneratesCorrectMessage()
+        {
+            _service.SendNotification("Student", "1", "John Doe", EntityOperation.CREATE, "Admin");
+            var notification = _service.ReceiveNotification();
+
+            Assert.NotNull(notification);
+            Assert.Equal("New Student 'John Doe' has been created", notification.Message);
+            Assert.Equal("Student", notification.EntityType);
+            Assert.Equal("1", notification.EntityId);
+            Assert.Equal("CREATE", notification.Operation);
+            Assert.Equal("Admin", notification.CreatedBy);
+            Assert.False(notification.IsRead);
+        }
+
+        [Fact]
+        public void SendNotification_WithDisplayName_Update_GeneratesCorrectMessage()
+        {
+            _service.SendNotification("Course", "101", "Chemistry", EntityOperation.UPDATE);
+            var notification = _service.ReceiveNotification();
+
+            Assert.NotNull(notification);
+            Assert.Equal("Course 'Chemistry' has been updated", notification.Message);
+        }
+
+        [Fact]
+        public void SendNotification_WithDisplayName_Delete_GeneratesCorrectMessage()
+        {
+            _service.SendNotification("Department", "5", "Engineering", EntityOperation.DELETE);
+            var notification = _service.ReceiveNotification();
+
+            Assert.NotNull(notification);
+            Assert.Equal("Department 'Engineering' has been deleted", notification.Message);
+        }
+
+        [Fact]
+        public void SendNotification_WithoutDisplayName_FallsBackToIdFormat()
+        {
+            _service.SendNotification("Student", "42", EntityOperation.CREATE);
+            var notification = _service.ReceiveNotification();
+
+            Assert.NotNull(notification);
+            Assert.Equal("New Student (ID: 42) has been created", notification.Message);
+        }
+
+        [Fact]
+        public void SendNotification_WithoutDisplayName_Update_UsesIdFormat()
+        {
+            _service.SendNotification("Course", "101", EntityOperation.UPDATE);
+            var notification = _service.ReceiveNotification();
+
+            Assert.NotNull(notification);
+            Assert.Equal("Course (ID: 101) has been updated", notification.Message);
+        }
+
+        [Fact]
+        public void SendNotification_WithoutDisplayName_Delete_UsesIdFormat()
+        {
+            _service.SendNotification("Instructor", "7", EntityOperation.DELETE);
+            var notification = _service.ReceiveNotification();
+
+            Assert.NotNull(notification);
+            Assert.Equal("Instructor (ID: 7) has been deleted", notification.Message);
+        }
+
+        [Fact]
+        public void SendNotification_NullUserName_DefaultsToSystem()
+        {
+            _service.SendNotification("Student", "1", "Test", EntityOperation.CREATE);
+            var notification = _service.ReceiveNotification();
+
+            Assert.NotNull(notification);
+            Assert.Equal("System", notification.CreatedBy);
+        }
+
+        [Fact]
+        public void SendNotification_WithUserName_UsesProvidedUser()
+        {
+            _service.SendNotification("Student", "1", "Test", EntityOperation.CREATE, "JohnAdmin");
+            var notification = _service.ReceiveNotification();
+
+            Assert.Equal("JohnAdmin", notification!.CreatedBy);
+        }
+
+        [Fact]
+        public void ReceiveNotification_EmptyQueue_ReturnsNull()
+        {
+            var notification = _service.ReceiveNotification();
+            Assert.Null(notification);
+        }
+
+        [Fact]
+        public void ReceiveNotification_DequeusFIFO()
+        {
+            _service.SendNotification("Student", "1", "First", EntityOperation.CREATE);
+            _service.SendNotification("Student", "2", "Second", EntityOperation.CREATE);
+
+            var first = _service.ReceiveNotification();
+            var second = _service.ReceiveNotification();
+
+            Assert.Contains("First", first!.Message);
+            Assert.Contains("Second", second!.Message);
+        }
+
+        [Fact]
+        public void ReceiveNotification_RemovesFromQueue()
+        {
+            _service.SendNotification("Student", "1", "Test", EntityOperation.CREATE);
+            var first = _service.ReceiveNotification();
+            var second = _service.ReceiveNotification();
+
+            Assert.NotNull(first);
+            Assert.Null(second);
+        }
+
+        [Fact]
+        public void SendNotification_SetsCreatedAt()
+        {
+            var before = DateTime.Now;
+            _service.SendNotification("Student", "1", "Test", EntityOperation.CREATE);
+            var after = DateTime.Now;
+            var notification = _service.ReceiveNotification();
+
+            Assert.NotNull(notification);
+            Assert.InRange(notification.CreatedAt, before, after);
+        }
+
+        [Fact]
+        public void MarkAsRead_DoesNotThrow()
+        {
+            var exception = Record.Exception(() => _service.MarkAsRead(999));
+            Assert.Null(exception);
+        }
+
+        [Fact]
+        public void Dispose_DoesNotThrow()
+        {
+            var exception = Record.Exception(() => _service.Dispose());
+            Assert.Null(exception);
+        }
+
+        [Fact]
+        public void SendNotification_NullDisplayName_FallsBackToIdFormat()
+        {
+            _service.SendNotification("Student", "1", (string?)null!, EntityOperation.CREATE);
+            var notification = _service.ReceiveNotification();
+
+            Assert.NotNull(notification);
+            Assert.Equal("New Student (ID: 1) has been created", notification.Message);
+        }
+
+        [Fact]
+        public void SendNotification_EmptyDisplayName_FallsBackToIdFormat()
+        {
+            _service.SendNotification("Student", "1", "", EntityOperation.CREATE);
+            var notification = _service.ReceiveNotification();
+
+            Assert.NotNull(notification);
+            Assert.Equal("New Student (ID: 1) has been created", notification.Message);
+        }
+
+        [Fact]
+        public void SendNotification_WhitespaceDisplayName_FallsBackToIdFormat()
+        {
+            _service.SendNotification("Student", "1", "   ", EntityOperation.CREATE);
+            var notification = _service.ReceiveNotification();
+
+            Assert.NotNull(notification);
+            Assert.Equal("New Student (ID: 1) has been created", notification.Message);
+        }
+    }
+}
+
